(window.webpackJsonp=window.webpackJsonp||[]).push([[10],{218:function(t,v,_){"use strict";_.r(v);var s=_(0),p=Object(s.a)({},(function(){var t=this,v=t.$createElement,_=t._self._c||v;return _("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[_("h1",{attrs:{id:"贫穷-自尊"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#贫穷-自尊"}},[t._v("#")]),t._v(" 贫穷-自尊")]),t._v(" "),_("p",[t._v("我大学的时候有个同学，那年过生日请几个朋友在学校外面的大排档吃了个晚饭，大概花了一百多块钱的样子。那几个朋友图个高兴，去蛋糕店买了一个蛋糕给他，过生日总算有点过生日的样子。蛋糕在大排档吃了一半，剩下的一半他没舍得扔掉，打包拿回宿舍当了三天的早餐吃。")]),t._v(" "),_("p",[t._v("第二天，他收到一个从老家寄来的快递，打开一看高兴坏了，是一双耐克篮球鞋。他妈妈知道他喜欢打篮球，省吃俭用几个月，花了五百块钱给他买了双打四折的耐克牌篮球鞋。他可宝贝那双球鞋了，他也知道那双球鞋是妈妈多么沉重的爱。")]),t._v(" "),_("p",[t._v("以前打球，我们都有球鞋，他没有。而且，他不会穿好鞋子，因为打球真的很费鞋，他会把以前不要的破鞋拿出来打球用，有开裂的，有发黄的，还有些时候我们不要的球鞋准备扔了，他会说给他，反正大家都是朋友，没什么不好意思的。自从有了那双耐克球鞋后，每次打球的时候都很开心。打球回来会马上把鞋子脱下来，用鞋刷刷一遍放好，那是他最珍贵的东西。")]),t._v(" "),_("p",[t._v("很多时候我真的不想去揣测人心是恶的，可是那一年却让我很难过，那个同学贫困生助学金被取消了，原因是他既然都能买得起耐克球鞋了，还算什么贫困生。那个同学一个人在宿舍里哭了很久，那双篮球鞋他再也没有穿过，也不会再去篮球场上打球了。")]),t._v(" "),_("p",[t._v("其实我知道那双球鞋是一个母亲用尽全部力量给孩子的爱，每一个母亲都这样。就像我自己，高中的时候，我妈妈总是觉得两百块钱一件的T恤太贵了，她自己从来不舍得买，但给我买的时候会毫不犹豫。我想每一个母亲都是这样，会把最好的给孩子，会不遗余力地希望孩子幸福开心，不要自卑。")]),t._v(" "),_("p",[t._v("我不知道那时候是谁和老师告的状，我很鄙视那样的人。五百块钱的篮球鞋是一个母亲给孩子的爱，和贫富没有关系。也许母亲一辈子不舍得买那么贵的鞋，但是为了孩子，她会在自己身上扣下一分一厘，慢慢攒着去换孩子一个开心的笑容。我不知道那些嚼舌根子告状的人是看不见还是没有想过。")]),t._v(" "),_("p",[t._v("不要总觉得贫穷的人就不能穿一件好看的衣服，贫穷的人就不能吃一顿体面的食物，贫穷的人就永远需要仰视你们的生活，贫穷的人就不该穿梭在你们的日常之间。")]),t._v(" "),_("p",[t._v("我曾听见最恶毒的话莫过于，贫困生就应该有贫困生的样子。我想问一下，贫困生是什么样子，是只能穿得破烂？不能有一点爱美之心？还是应该把尊严丢弃，然后在怜悯的目光下生存？")]),t._v(" "),_("p",[t._v("那个同学没了助学金，他没有去申诉。有一次我和他说，你去和老师讲讲，我可以帮你作证，那篮球鞋是你妈妈攒了很久给你买的礼物。他笑了笑说，别了，挺丢人的，没事的，钱给更有需要的同学。后来他去做兼职，晚上去酒吧当服务员，白天跑回来上课，因为他不敢和妈妈说助学金没了。那些助学金是他几个月的生活费，说没就没了，他只能靠自己去挣。")]),t._v(" "),_("p",[t._v("这件事我一直耿耿于怀，我想如果我知道是谁嚼舌根子，我一定会替那个同学揍他一顿。为什么一个穷孩子穿一次耐克鞋就会受到这样的待遇，你没有看见他多宝贝那双鞋子。也许在你的心里觉得那只是一双普通的名牌鞋，也不是很贵，是花点钱就可以买到的虚荣，但是在他眼里不是，那是母亲的爱，是生活里的大事件，可能也是一生中最难忘最贵重的礼物。")]),t._v(" "),_("p",[t._v("没有穷过的人不会明白，像我这般深深贫穷过的人在贫穷的时候是多么渴望和有钱人一样可以有漂亮的衣服，可以吃好吃的零食。记得第一次爸妈为了给我买一双某品牌的鞋子，进进出出专卖店四次，硬生生把两百多的鞋子一百多块钱买来。那个店主很不耐烦，其他客人也一直看着我爸妈，店主最后几乎是一边白眼一边把鞋子卖给我的。我那时候一边眼里含着眼泪，一边又很欢喜自己终于有一双漂亮有牌子的鞋子了，那种屈辱又开心的心情，有谁能明白？\n贫穷已经剥夺了一个人在这个世上的很多种快乐，请不要再以贫穷去肆意践踏他们的尊严。一双五百块钱的球鞋对你而言或许是一种虚荣有钱的体现，但对于真正有困难的人来讲，那双球鞋是来自他不曾触摸到的世界的惊喜。他踩在板凳上，仰起头，一双球鞋暂时让他觉得靠近了大家的距离。可是那些残忍的人为什么要一脚踢翻了板凳？你们没有看见他的脖子上拴着一条叫做尊严的麻绳吗？")]),t._v(" "),_("p",[_("br"),_("br")]),t._v(" "),_("div",{staticClass:"custom-block tip"},[_("p",{staticClass:"custom-block-title"},[t._v("感想")]),t._v(" "),_("p",[t._v("（高中入学的第一天，我妈妈也带我去鸿星尔克买了一双运动鞋，那是我第一双名牌鞋，我记得非常清楚，那天晚上回到家我端着那双鞋，反复看了好久，非常宝贝，我现在甚至还清楚的记得那双鞋子的款式，我也记得当时鸿星尔克搞活动，各种满减的优惠，我妈妈心里一直在计算着金额，说服务员算错了，我觉得有点丢人，说服务员怎么会算错，语气很不耐烦，觉得她在让我处于尴尬的境地，后来服务员重新算一遍，果然是算错了。那时候自尊心比较强，贫穷使它更敏感）")])])])}),[],!1,null,null,null);v.default=p.exports}}]);